package distributedwallet

import (
	"context"
	"encoding/hex"
	"strings"
	"sync"

	"github.com/attestantio/go-eth2-client/spec/phase0"
	"github.com/pkg/errors"
	e2w "github.com/wealdtech/go-eth2-wallet"
	scratch "github.com/wealdtech/go-eth2-wallet-store-scratch"
	e2wt "github.com/wealdtech/go-eth2-wallet-types/v2"
)

const (
	passphrase   = "thisisaverylongsentencelotsofentropy"
	signerTest01 = ""
	signerTest02 = ""
	signerTest03 = ""
	signerTest04 = ""
	signerTest05 = ""

	DistributedAccountPubkeyStr = "0x984c6bcde66a1af55d6484e4ab8648c2357b7e4869587396cd3790995f70cfdcadee4015a109e35491744bffff27a49b"
)

var DistributedAccountPubkey phase0.BLSPubKey

var wallets = [6][]byte{}

func init() {
	var err error
	distributedAccountPubkeyBytes, err := hex.DecodeString(strings.TrimPrefix(DistributedAccountPubkeyStr, "0x"))
	if err != nil {
		panic(err)
	}
	DistributedAccountPubkey = phase0.BLSPubKey(distributedAccountPubkeyBytes)
	wallets[1], err = hex.DecodeString(strings.TrimPrefix(signerTest01, "0x"))
	if err != nil {
		panic(err)
	}
	wallets[2], err = hex.DecodeString(strings.TrimPrefix(signerTest02, "0x"))
	if err != nil {
		panic(err)
	}
	wallets[3], err = hex.DecodeString(strings.TrimPrefix(signerTest03, "0x"))
	if err != nil {
		panic(err)
	}
	wallets[4], err = hex.DecodeString(strings.TrimPrefix(signerTest04, "0x"))
	if err != nil {
		panic(err)
	}
	wallets[5], err = hex.DecodeString(strings.TrimPrefix(signerTest05, "0x"))
	if err != nil {
		panic(err)
	}
}

var mux = sync.Mutex{}

func WalletSigner(ctx context.Context, id int) (e2wt.Wallet, error) {
	mux.Lock()
	defer mux.Unlock()
	err := e2w.UseStore(scratch.New())
	if err != nil {
		return nil, errors.Wrap(err, "failed to use store")
	}
	w, err := e2w.ImportWallet(wallets[id], []byte(passphrase))
	if err != nil {
		return nil, errors.Wrap(err, "failed to import wallet")
	}
	return w, nil
}
